      print(f'  Matched MUL*FLOORMOD: base={base.op}, div={div}, mul={mul}')
    else: 
      print(f'  Did not match any pattern')
      continue
    for j,v in enumerate(terms):
      if i == j: continue
      print(f'  Checking term {j}: v.op={v.op}')
      if v.op is not Ops.MUL or v.src[1].op is not Ops.CONST or v.src[1].arg != div*mul: 
        print(f'    Skipping: v.op is not MUL={v.op is not Ops.MUL}, src[1].op is not CONST={v.src[1].op is not Ops.CONST}, arg mismatch={v.src[1].arg != div*mul}')
        continue
      q, exact = v.src[0], False
      print(f'    q={q.op}, div*mul={div*mul}')
      # (base%div)*mul + (base//div)*(div*mul) -> base*mul
      if q.op is Ops.FLOORDIV and q.src[1].op is Ops.CONST and q.src[1].arg == div: 
        exact = q.src[0] is base
        print(f'    First pattern: q.op is FLOORDIV, arg matches div={q.src[1].arg == div}, exact={exact}')
      # ((base//d)%div)*mul + (base//(d*div))*(div*mul) -> (base//d)*mul if div>0
      if not exact and div > 0 and base.op is Ops.FLOORDIV and base.src[1].op is Ops.CONST:
        exact = q.op is Ops.FLOORDIV and q.src[1].op is Ops.CONST and q.src[0] is base.src[0] and q.src[1].arg == base.src[1].arg*div
        print(f'    Second pattern: base is FLOORDIV, exact={exact}')
      if exact: 
        print(f'    Returning simplified!')
        return (base*mul).usum(*[t for k,t in enumerate(terms) if k not in (i,j)])
      # ((base//div)%d)*(div*mul) + (base%div)*mul -> (base%(div*d))*mul
      if div > 0 and q.op is Ops.FLOORMOD and q.src[1].op is Ops.CONST and (d:=q.src[1].arg) > 0 and q.src[0].op is Ops.FLOORDIV:
        if q.src[0].src[0] is base and q.src[0].src[1].op is Ops.CONST and q.src[0].src[1].arg == div:
          print(f'    Third pattern matched!')
          return ((base % (div*d))*mul).usum(*[t for k,t in enumerate(terms) if k not in (i,j)])
  return None

